class Temperature private constructor(val kelvin: Double) {
    companion object {
        fun fromCelsius(c: Double) = Temperature(c + 273.15)
        fun fromFahrenheit(f: Double) = fromCelsius((f - 32) / 1.8)
    }
}

class CountingList<T>(
    private val inner: MutableList<T> = mutableListOf()
) : MutableList<T> by inner {
    var adds = 0; private set
    override fun add(element: T): Boolean {
        adds++
        return inner.add(element)
    }
}

